-- سكريبت إضافة الدفعة الثالثة: 100 مصطلح رياضي شامل ومراجع لغوياً (الإصدار 3)

INSERT INTO words (
    word, arabic_title, part_of_speech, arabic_transliteration, syllables, syllables_arabic_guide,
    math_definition, general_definition, ipa_us, ipa_uk, example_math_1, example_math_2, 
    example_classroom, common_mistakes, educational_level, category_id
) VALUES 

-- [1-10] كلمات أساسية ومشتركة (مكملة)
('Denominator', 'المقام', 'Noun', 'دِينُومِنَاتُر', 'De·nom·i·na·tor', 'De: دِي | nom: نُومْ | i: مِـ | na: نَا | tor: تُر', 'The quantitative numeral written below the fractional line, indicating the total number of equal parts into which the whole is divided.', 'A shared characteristic or standard used for comparison.', '/dɪˈnɑː.mə.neɪ.tər/', '/dɪˈnɒm.ɪ.neɪ.tər/', 'To add these fractions, we must first find a common denominator.', 'The variable expression in the denominator cannot equal zero.', '“Look at the fraction two-fifths. Five is our denominator, telling us the whole is divided into five equal pieces.”', 'Ensure you do not stress the first syllable flatly.', 'Primary School', 1),
('Decimal', 'العلامة العشرية / كسر عشري', 'Noun', 'دِيسِيمَل', 'Dec·i·mal', 'Dec: دِيـسْ | i: مِـ | mal: مَل', 'A fraction whose denominator is a power of ten, systematically expressed by points placed to the left of the numerator.', 'Relating to or denoted by a system of numbers and monetary units based on the number ten.', '/ˈdes.ə.məl/', '/ˈdes.ɪ.məl/', 'Convert the vulgar fraction three-quarters into its equivalent decimal form, which is zero point seven five.', 'When aligning numbers for addition, ensure the decimal points are perfectly stacked.', '“Look at the number two point five. The dot between two and five is called the decimal point.”', 'Students often misread 0.15 as bigger than 0.2 because fifteen is bigger than two.', 'Primary School', 1),
('Percentage', 'النسبة المئوية', 'Noun', 'بَرسِينْتِج', 'Per·cent·age', 'Per: بَر | cent: سِينْـ | age: تِج', 'A rate, number, or amount calculated as a particular proportion or fraction out of every hundred.', 'A specific proportion or share of a whole financial or physical entity.', '/pərˈsen.t̬ɪdʒ/', '/pəˈsen.tɪdʒ/', 'To calculate the percentage profit, divide the net gain by the original cost and multiply by one hundred.', 'What percentage of the class passed the advanced calculus diagnostic assessment?', '“If you got eighty marks out of a hundred on your quiz, your score is exactly eighty percentage or eighty percent.”', 'Ensure the stress is properly placed on the second syllable: /sen/.', 'Primary / Preparatory', 1),
('Mean', 'المتوسط الحسابي / الوسط', 'Noun', 'مِين', 'Mean', 'Mean: مِين', 'The mathematical average of a set of numerical values, calculated by dividing the sum of the values by their total count.', 'An intermediate state or course of action between two extremes.', '/miːn/', '/miːn/', 'To find the mean of the data set, add all the test scores together and divide by the number of students.', 'The arithmetic mean can be heavily influenced by extreme outlier values.', '“If we have three numbers: two, four, and six. Their sum is twelve. Divide by three, so our mean is four.”', 'Often confused with "Median" (الوسيط) or "Mode" (المنوال).', 'Preparatory School', 4),
('Median', 'الوسيط', 'Noun', 'مِيدِيَن', 'Me·di·an', 'Me: مِي | di: دِي | an: يَن', 'The middle number in a given sequence of numbers that are ordered or arranged from lowest to highest.', 'The strip of land or physical barrier separating opposing lanes of traffic on a highway.', '/ˈmiː.di.ən/', '/ˈmiː.di.ən/', 'To find the median, first arrange the raw numbers in ascending order.', 'If the data set has an even number of observations, the median is the average of the two middle scores.', '“Line up all numbers from smallest to biggest. The exact middle number standing there is our median.”', 'Do not forget to sort the data set before locating the middle element.', 'Preparatory School', 4),
('Mode', 'المنوال', 'Noun', 'مُود', 'Mode', 'Mode: مُود', 'The specific value or number that appears most frequently in a particular data set sequence.', 'A particular way, method, or style of doing something or operating.', '/moʊd/', '/məʊd/', 'A data distribution sequence can be unimodal, bimodal, or possess no mode at all.', 'The empirical mode of this statistical sample is exactly fifteen.', '“Look at this list of scores. The number that repeats the most times is called the mode.”', 'Students sometimes think a data set must always have a mode. Explain that it is optional.', 'Preparatory School', 4),
('Ratio', 'النسبة', 'Noun', 'رِيشْيُو', 'Ra·tio', 'Ra: رِيشْ | tio: يُو', 'The quantitative relation between two numerical amounts showing the number of times one value contains or is contained within the other.', 'The relative scale or proportion between different non-mathematical components.', '/ˈreɪ.ʃi.oʊ/', '/ˈreɪ.ʃi.əʊ/', 'The ratio of boys to girls in our mathematics classroom is exactly three to two.', 'Express the final structural ratio in its simplest reduced form.', '“If we have three blue balls and two red balls, the ratio of blue to red is written as three to two.”', 'Pronounce the "ti" as a soft "sh" sound (/ˈreɪ.ʃi.oʊ/), not a flat "t" sound.', 'Primary / Preparatory', 1),
('Proportion', 'التناسب', 'Noun', 'بْرُوبُورْشَن', 'Pro·por·tion', 'Pro: بْرو | por: بْور | tion: شَن', 'A mathematical statement or mathematical equation asserting that two ratios are perfectly equal to each other.', 'The correct, harmonious, or desirable relationship between parts of a whole.', '/prəˈpɔːr.ʃən/', '/prəˈpɔː.ʃən/', 'We can solve the proportion equation by performing cross-multiplication across the terms.', 'The dimensions of the regular geometric shapes are in perfect proportion.', '“A proportion means that two ratios are completely equal, like saying one-half is the same as two-quarters.”', 'Avoid stressing the first syllable; the main rhythm rises on the second part: /ˈpɔːr/.', 'Preparatory School', 1),
('Angle', 'زاوية', 'Noun', 'أَنْجَل', 'An·gle', 'An: أَنْ | gle: جَل', 'The distinct space or measurement between two intersecting lines or surfaces at the point where they originate.', 'A particular way of approaching, considering, or evaluating a complex problem.', '/ˈæŋ.ɡəl/', '/ˈæŋ.ɡəl/', 'The sum of the interior angles of any planar triangle always equals one hundred and eighty degrees.', 'Measure the designated reflex angle using a standard geometry protractor.', '“When two straight lines meet at one corner point, the space inside that corner forms an angle.”', 'Watch out for spelling or pronunciation confusions with the word "Angel" (ملاك). It is "An-g-el".', 'Primary School', 3),
('Vertex', 'رأس الزاوية / رأس الشكل', 'Noun', 'فِيرْتِكْس', 'Ver·tex', 'Ver: فِيرْ | tex: تِكْس', 'The highest point, apex, or intersection point where two or more straight geometric lines or curves meet.', 'The highest point of achievement or the literal summit of a physical structure.', '/ˈvɜːr.teks/', '/ˈvɜː.teks/', 'A standard triangle features three distinct vertices and three connecting linear edges.', 'The vertex of the quadratic parabola function represents its absolute minimum point.', '“The sharp corner point where the two lines of our angle meet is called the vertex.”', 'The plural form of "Vertex" is "Vertices". Make sure students learn both variants.', 'Primary / Preparatory', 3),

-- [11-30] مصطلحات الهندسة والأشكال (Geometry & Shapes)
('Polygon', 'مضلع', 'Noun', 'بُولِيجَان', 'Pol·y·gon', 'Pol: بُو | y: لِـ | gon: جَان', 'A flat, two-dimensional closed geometric shape bounded by three or more straight line segments.', 'Any multifaceted commercial entity or structurally complex physical framework.', '/ˈpɑː.li.ɡɑːn/', '/ˈpɒl.i.ɡɒn/', 'A regular polygon has interior angles that are all perfectly equal to one another.', 'An octagon is a closed planar polygon possessing exactly eight linear sides.', '“Any flat shape made with only straight lines connected together, like a triangle or square, is a polygon.”', 'Do not pronounce the ending like "gun". It is a clear open sound: /ɡɑːn/ or /ɡɒn/.', 'Primary School', 3),
('Diagonal', 'القطر (في شكل هندسي)', 'Noun', 'دَايَاجُونَل', 'Di·ag·o·nal', 'Di: دَا | ag: يَا | o: جُو | nal: نَل', 'A straight line segment joining two non-adjacent vertices of a polygon or polyhedron shape.', 'A slanted or oblique direction or movement across a physical surface plane.', '/daɪˈæɡ.ən.əl/', '/daɪˈæɡ.ən.əl/', 'The diagonal of a square cuts the geometric area into two right isosceles triangles.', 'Calculate the total length of the internal rectangular diagonal vector.', '“If you draw a straight line from one corner of the room directly to the opposite corner, that is a diagonal.”', 'Pronounce the stress clearly on the second syllable: /ˈæɡ/.', 'Primary / Preparatory', 3),
('Diameter', 'قطر الدائرة', 'Noun', 'دَايَامِيتُر', 'Di·am·e·ter', 'Di: دَا | am: يَا | e: مِـ | ter: تُـر', 'A straight line segment that passes directly through the center of a circle and touches both edges.', 'The transverse width or thickness of any cylindrical or spherical physical object.', '/daɪˈæm.ə.t̬ər/', '/daɪˈæm.ɪ.tər/', 'The diameter of a circle is calculated as exactly twice the length of its radius distance.', 'Measure the maximum outer diameter of the circular cylindrical metal pipe.', '“If you draw a straight line from one side of a circle to the other, passing right through the center dot, that is the diameter.”', 'Do not confuse "Diameter" with "Diagonal". Diameter is exclusively for circular/curved lines.', 'Primary School', 3),
('Radius', 'نصف قطر الدائرة', 'Noun', 'رِيدْيَس', 'Ra·di·us', 'Ra: رِيدْ | di: ِـ | us: يَس', 'A straight line segment extending from the exact center point of a circle or sphere to its outer boundary.', 'A specific circular area of distance measured outward from a central focus point.', '/ˈreɪ.di.əs/', '/ˈreɪ.di.əs/', 'The area of a circle equals pi multiplied by the square of the internal radius.', 'We need to adjust the drawing compass to a radius setting of exactly four centimeters.', '“The distance from the exact center of the bicycle wheel out to the outer edge is the radius.”', 'The plural form of "Radius" is "Radii" (pronounced /ˈreɪ.di.aɪ/).', 'Primary School', 3),
('Circumference', 'محيط الدائرة', 'Noun', 'سِركَامْفِرَانْس', 'Cir·cum·fer·ence', 'Cir: سِر | cum: كَامْـ | fer: فِـر | ence: أَنْس', 'The continuous outer boundary line or total perimeter distance enclosing a circular geometric shape.', 'The outer boundary limits or total enclosing framework of a specific physical situation.', '/səˈkʌm.fər.əns/', '/səˈkʌm.fər.əns/', 'The formula for calculating the circumference of any circle is two times pi times radius.', 'We wrapped the measuring tape around the tree trunk to find its exact circumference.', '“The circumference is just a special name for the perimeter of a circle. It is the total length of the outer curved line.”', 'This word is long and tricky to spell. Practice splitting it into segments with your students.', 'Primary School', 3),
('Triangle', 'مثلث', 'Noun', 'تْرَايَانْجَل', 'Tri·an·gle', 'Tri: تْرَايْ | an: أَنْـ | gle: جَل', 'A closed flat polygon possessing exactly three straight line sides and three internal angles.', 'A situation involving three separate people, groups, or competing elements.', '/ˈtraɪ.æŋ.ɡəl/', '/ˈtraɪ.æŋ.ɡəl/', 'An isosceles triangle features two sides that are perfectly equal in structural length.', 'The area of a planar triangle is computed as half base times perpendicular height.', '“A triangle has three sharp corners and three straight sides, like a slice of pizza.”', 'Ensure the hard /ɡ/ sound is maintained at the end, not soft like a "j".', 'Primary School', 3),
('Square', 'مربع', 'Noun / Adj', 'سْكْوِير', 'Square', 'Square: سْكْوِير', 'A regular quadrilateral polygon with four perfectly equal straight sides and four ninety-degree right angles.', 'An open public area in a city, or a product multiplied by itself.', '/skwer/', '/skweər/', 'The surface area of a square is calculated by squaring the length of its side.', 'Each internal corner of a regular square forms a perfect right angle.', '“A square has four sides that are completely equal, and all its corners are perfectly straight.”', 'Keep the vowel crisp and clear, avoid flattening the ending.', 'Primary School', 3),
('Parallelogram', 'متوازي أضلاع', 'Noun', 'بَارَالِيلُوجْرَام', 'Par·al·lel·o·gram', 'Par: بَا | al: رَا | lel: لِـيلْ | o: و | gram: جْرَام', 'A flat quadrilateral polygon whose opposite sides are perfectly parallel and equal in length.', 'A specific commercial graphic design shape or physical structural profile.', '/ˌpær.əˈlel.ə.ɡræm/', '/ˌpær.əˈlel.ə.ɡræm/', 'The opposite internal angles of a geometric parallelogram are completely congruent.', 'Find the total surface area of the parallelogram using base times height.', '“Think of a parallelogram as a rectangle that is leaning slightly to one side.”', 'This is a long word. Teach students to break it down into "parallel" and "gram".', 'Primary / Preparatory', 3),
('Rhombus', 'معين', 'Noun', 'رَامْبَس', 'Rhom·bus', 'Rhom: رَامْـ | bus: بَس', 'A flat quadrilateral polygon possessing four straight sides that are completely equal in length.', 'An oblique or diamond-shaped geometric configuration or physical framework.', '/ˈrɑːm.bəs/', '/ˈrɒm.bəs/', 'The internal diagonals of a regular rhombus always intersect at a perfect ninety-degree angle.', 'Every regular square qualifies as a rhombus, but not every rhombus is a square.', '“A rhombus looks like a diamond. All four of its straight sides are perfectly equal in length.”', 'The letter "h" is completely silent. Pronounce it directly as "Ram-bus".', 'Primary / Preparatory', 3),
('Trapezoid', 'شبه منحرف', 'Noun', 'تْرَابِيزُويْد', 'Trap·e·zoid', 'Trap: تْرَا | e: بِـ | zoid: زُويْد', 'A flat quadrilateral polygon possessing exactly one pair of parallel straight sides.', 'A physical support frame or bone structural shape in anatomy.', '/ˈtræp.ə.zɔɪd/', '/ˈtræp.ɪ.zɔɪd/', 'The parallel sides of a geometric trapezoid are referred to as its upper and lower bases.', 'Calculate the surface area of the trapezoid using the average of both parallel bases.', '“A trapezoid has only two sides that run parallel like train tracks, while the other two meet up.”', 'In British English, this shape is called a "Trapezium". It is good to mention both.', 'Primary / Preparatory', 3),
('Pentagon', 'شكل خماسي الأضلاع', 'Noun', 'بِينْتَاجَان', 'Pen·ta·gon', 'Pen: بِينْـ | ta: تَا | gon: جَان', 'A closed planar polygon geometric shape featuring exactly five straight sides and five internal angles.', 'A large government structural headquarters, or any five-sided physical object.', '/ˈpen.tə.ɡɑːn/', '/ˈpen.tə.ɡɒn/', 'The sum of the interior angles of a regular flat pentagon always equals 540 degrees.', 'Draw a perfect regular pentagon inside the geometric workspace circle.', '“A pentagon is any flat shape that has exactly five straight sides, like a small house drawing.”', 'The primary stress lands heavily on the first syllable: /ˈpen/.', 'Primary School', 3),
('Hexagon', 'شكل سداسي الأضلاع', 'Noun', 'هِكْسَاجَان', 'Hex·a·gon', 'Hex: هِكْسْ | a: َـ | gon: جَان', 'A closed planar polygon geometric shape featuring exactly six straight sides and six internal angles.', 'The structural shape observed in natural honeycomb cells constructed by bees.', '/ˈhek.sə.ɡɑːn/', '/ˈhek.sə.ɡɒn/', 'A regular hexagon can be perfectly split into six identical equilateral triangles.', 'The floor tiles were manufactured in the shape of a regular symmetric hexagon.', '“Think of a beehive honeycomb. Each little cell is a perfect hexagon with six sides.”', 'Ensure the "x" sound is crisp and sharp like an "ks" cluster.', 'Primary School', 3),
('Octagon', 'شكل ثماني الأضلاع', 'Noun', 'أُكْتَاجَان', 'Oc·ta·gon', 'Oc: أُكْـ | ta: تَا | gon: جَان', 'A closed planar polygon geometric shape featuring exactly eight straight sides and eight internal angles.', 'The standard physical shape used worldwide for automobile stop signs.', '/ˈɑːk.tə.ɡɑːn/', '/ˈɒk.tə.ɡɒn/', 'The internal angles of a regular symmetric octagon each measure exactly 135 degrees.', 'The martial arts tournament takes place inside an enclosed chain-link octagon framework.', '“A standard red stop sign on the street is a perfect example of an octagon because it has eight sides.”', 'Keep the open /ɑː/ or /ɒ/ sound clear in the final syllable.', 'Primary School', 3),
('Perpendicular', 'عمودي على', 'Adj / Noun', 'بِربِينْدِكْيُلَر', 'Per·pen·dic·u·lar', 'Per: بِر | pen: بِينْـ | dic: دِكْـ | u: يـُ | lar: لَر', 'A geometric relationship where two lines intersect at a perfect ninety-degree right angle.', 'An upright or vertical physical position relative to a flat horizontal surface plane.', '/ˌpɜːr.pənˈdɪk.jə.lər/', '/ˌpɜː.pənˈdɪk.jə.lər/', 'The altitude of a triangle is always perpendicular to its horizontal base line.', 'Construct a line that runs perfectly perpendicular to the given segment through point P.', '“When two lines cross each other making a perfect square corner, we say they are perpendicular.”', 'This is a long word. Practice alternating the stresses on /ˈpən/ and /ˈdɪk/.', 'Primary / Preparatory', 3),
('Parallel', 'موازي لـ', 'Adj / Noun', 'بَارَالِيل', 'Par·al·lel', 'Par: بَا | al: رَا | lel: لِـيلْ', 'Lines or planes that remain a constant equal distance apart and never intersect, no matter how far extended.', 'A person or situation that is directly comparable or completely similar to another.', '/ˈpær.ə.lel/', '/ˈpær.ə.lel/', 'The opposite railway tracks must run completely parallel to prevent train derailment.', 'Line AB is perfectly parallel to line CD in this geometric proofs layout.', '“Parallel lines run side-by-side like train tracks and will never, ever meet or cross each other.”', 'Spelling tip: Notice that the word has a double "ll" in the middle, looking like parallel lines!', 'Primary School', 3),
('Intersecting', 'متقاطع', 'Adj / Verb', 'إِنْتَرسِكْتِينْج', 'In·ter·sect·ing', 'In: إِنْـ | ter: تَر | sect: سِكْـ | ing: تِينْج', 'Lines or geometric pathways that cross over or meet each other at a single common point.', 'Two different topics or physical paths that come together or share common features.', '/ˌɪn.t̬ərˈsek.tɪŋ/', '/ˌɪn.təˈsek.tɪŋ/', 'The two intersecting lines create two pairs of identical vertically opposite angles.', 'Determine the precise grid coordinates where the two linear functions are intersecting.', '“When two roads cross each other at a junction, we say they are intersecting lines.”', 'Ensure the ending is pronounced with a nasal /ŋ/ rather than a flat "g".', 'Primary School', 3),
('Symmetry', 'التماثل / التناظر', 'Noun', 'سِيمِتْرِي', 'Sym·me·try', 'Sym: سِيمْـ | me: مِـ | try: تْرِي', 'The quality of being made up of exactly similar parts facing each other or around a central axis.', 'A balanced and beautiful proportion or harmony observed in artistic configurations.', '/ˈsɪm.ə.tri/', '/ˈsɪm.ɪ.tri/', 'A regular butterfly display showcases near-perfect bilateral structural symmetry.', 'Draw the line of reflection symmetry straight through the center of the shape.', '“If you fold a shape perfectly in half and both sides match exactly, that shape has symmetry.”', 'The stress falls on the very first syllable: /ˈsɪm/. Don''t say "sy-me-try".', 'Primary School', 3),
('Congruent', 'متطابق', 'Adj', 'كَانْجْرُوَنْت', 'Con·gru·ent', 'Con: كَانْجْـ | gru: رُو | ent: أَنْتْ', 'Geometric figures that have identical shapes and identical structural sizes.', 'Coinciding or agreeing completely with a specific logical plan or statement.', '/ˈkɑːŋ.ɡru.ənt/', '/ˈkɒŋ.ɡru.ənt/', 'Two triangles are proven congruent if all three corresponding sides are equal.', 'The base angles of an isosceles triangle are completely congruent to each other.', '“Congruent shapes are twins! They have the exact same size and the exact same shape.”', 'Ensure the "n" blends smoothly into a hard /ɡ/ sound, like "Kang-ru-ent".', 'Preparatory School', 3),
('Similar', 'متشابه (هندسياً)', 'Adj', 'سِيمِلَر', 'Sim·i·lar', 'Sim: سِيمْـ | i: مِـ | lar: لَر', 'Geometric figures that have the exact same shape but differ in their physical size scale.', 'Having a general resemblance or looking alike without being identical.', '/ˈsɪm.ə.lər/', '/ˈsɪm.ɪ.lər/', 'Similar triangles have equal corresponding angles but proportional corresponding sides.', 'The two architectural scale blueprints are mathematically similar in layout.', '“Similar shapes are like a father and son. They look exactly the same, but one is big and one is small.”', 'Remind students that in math, "similar" means proportional, not just looking generally alike.', 'Preparatory School', 3),
('Reflection', 'الانعكاس', 'Noun', 'رِيفْلِكْشَن', 'Re·flec·tion', 'Re: رِ| flec: فْلِكْـ | tion: شَن', 'A transformation that flips a geometric figure over a specified line, creating a mirror image.', 'The throwing back by a body or surface of light, heat, or sound waves.', '/rɪˈflek.ʃən/', '/rɪˈflek.ʃən/', 'The geometric reflection of point A across the y-axis yields negative coordinates.', 'Perform a standard linear reflection transformation on the given polygonal shape.', '“Think of looking in a mirror. A geometric reflection flips the shape over a line like a mirror image.”', 'Keep the "flec" syllable sharp and distinct.', 'Primary / Preparatory', 3),

-- [31-50] مصطلحات الجبر والمعادلات (Algebra & Functions)
('Coefficient', 'المعامل (في الجبر)', 'Noun', 'كُويِفِيشَنْت', 'Co·ef·fi·cient', 'Co: كُو | ef: إِفْ | fi: فِـي | cient: شَنْت', 'A numerical or constant quantity placed before and multiplying an algebraic variable expression.', 'A multiplier or statistical factor that measures a specific physical or chemical property.', '/ˌkoʊ.ɪˈfɪʃ.ənt/', '/ˌkəʊ.ɪˈfɪʃ.ənt/', 'In the algebraic expression four x squared, the numeral four is designated as the coefficient.', 'Identify the negative numeric coefficient associated with the linear variable term.', '“In the expression five y, the number five is the coefficient. It tells us exactly how many times we multiply y.”', 'Ensure students pronounce the middle "fish" sound softly: /ˈfɪʃ/.', 'Preparatory School', 2),
('Constant', 'الثابت (في الجبر)', 'Noun / Adj', 'كَانْسْتَانْت', 'Con·stant', 'Con: كَانْسْ | tant: تَالْت', 'A fixed numerical value or symbol in an algebraic expression that does not change its core value.', 'Occurring continuously or remaining completely unchanged over a long period of time.', '/ˈkɑːn.stənt/', '/ˈkɒn.stənt/', 'In the linear function equation y equals three x plus seven, the number seven is the constant.', 'The universal gravitational metrics remain perfectly constant across our calculations.', '“A constant is a lonely number with no letters attached to it, because its value stays exactly the same.”', 'Remind students that constants do not change, unlike variables which hold hidden mystery numbers.', 'Preparatory School', 2),
('Expression', 'المقدار / التعبير الجبري', 'Noun', 'إِكْسْبْرِشَن', 'Ex·pres·sion', 'Ex: إِكْسْ | pres: بْرِ| sion: شَن', 'A mathematical phrase containing numbers, operational operators, and variables, without an equal sign.', 'The look on someone''s face, or the action of making known one''s thoughts or feelings.', '/ɪkˈspreʃ.ən/', '/ɪkˈspreʃ.ən/', 'We must simplify the algebraic expression before attempting to evaluate its value.', 'The student successfully factored the quadratic expression written on the board.', '“An expression is a math phrase like three x plus two. Notice it doesn''t have an equal sign!”', 'Differentiate clearly between an "expression" and an "equation" for students.', 'Preparatory School', 2),
('Exponent', 'الأس', 'Noun', 'إِكْسْبُونَنْت', 'Ex·po·nent', 'Ex: إِكْسْ | po: بُو | nent: نَنْتْ', 'A quantity representing the power to which a given base number or expression is to be raised.', 'A person who supports an idea or theory and tries to persuade others of its truth.', '/ɪkˈspoʊ.nənt/', '/ɪkˈspəʊ.nənt/', 'In the mathematical term base x raised to power three, the numeral three is the exponent.', 'Apply the core laws of exponents to simplify the rational algebraic multiplication.', '“An exponent is the small floating number at the top. It tells the base number to multiply itself that many times.”', 'Also known as "Index" or "Power". It is helpful to introduce these synonyms.', 'Preparatory School', 2),
('Function', 'الدالة', 'Noun', 'فَانْكْشَن', 'Func·tion', 'Func: فَانْكْـ | tion: شَن', 'A mathematical relation where each specific input value maps to exactly one unique output value.', 'An activity or purpose natural to or intended for a person or structural thing.', '/ˈfʌŋk.ʃən/', '/ˈfʌŋk.ʃən/', 'The linear function maps variable x to a corresponding straight continuous coordinate line.', 'Determine the complete valid domain range of this rational square root function.', '“Think of a function as a math vending machine. You put in one input, and you get exactly one output reward.”', 'Keep the "k" sound in "func" crisp before sliding into the "shun" syllable.', 'Preparatory School', 2),
('Inequality', 'المتباينة', 'Noun', 'إِنإِيكْوَلِتِي', 'In·e·qual·i·ty', 'In: إِنْـ | e: إِ | qual: كْوَ | i: لِـ | ty: تِي', 'A mathematical statement asserting that two expressions are not equal, using greater than or less than.', 'The unfair situation in society where some people have more opportunities or money than others.', '/ˌɪn.ɪˈkwɑː.lə.t̬i/', '/ˌɪn.ɪˈkwɒl.ə.ti/', 'To solve this linear inequality, remember to flip the sign when multiplying by a negative.', 'Graph the complete solution set of the quadratic inequality on the coordinate number line.', '“An inequality shows that two math phrases are not equal. It uses signs like greater than or less than.”', 'Remind students of the critical rule: flip the inequality direction when multiplying or dividing by a negative number.', 'Preparatory School', 2),
('Linear', 'خطي', 'Adj', 'لِينِيَر', 'Lin·e·ar', 'Lin: لِـي | e: نِـ | ar: يَر', 'Arranged in or extending along a straight line, or relating to a function of the first degree.', 'Progressing from one stage to another in a single series of steps or sequential order.', '/ˈlɪn.i.ɚ/', '/ˈlɪn.i.ər/', 'The graph of a linear equation invariably forms a perfectly straight continuous line.', 'We are calculating the exact slope rate of change for this linear function template.', '“A linear equation is a straight-line equation. If you draw it on a grid, it makes a perfect straight line.”', 'Pronounce it as "Lin-ee-ar", avoiding flattening the middle vowel.', 'Preparatory School', 2),
('Quadratic', 'تربيعي / من الدرجة الثانية', 'Adj / Noun', 'كْوَدْرَاتِك', 'Quad·rat·ic', 'Quad: كْوَدْ | rat: رَا | ic: تِكْ', 'Relating to a mathematical expression or equation involving the square of a variable and no higher power.', 'An algebraic polynomial equation of the second degree.', '/kwɑːdˈræt̬.ɪk/', '/kwɒdˈræt.ɪk/', 'The standard continuous graph of a quadratic function forms a symmetric parabola curve.', 'Apply the general quadratic formula to find the two complex roots of the equation.', '“A quadratic equation has a variable squared, like x to the power of two, and its graph looks like a smile or a frown.”', 'The stress falls on the second syllable: /ˈræt/.', 'Preparatory / Secondary', 2),
('Sequence', 'المتتابعة / المتتالية', 'Noun', 'سِيكْوَنْس', 'Se·quence', 'Se: سِيكْـ | quence: وَنْسْ', 'An ordered list of numbers generated or structured according to a specific mathematical rule.', 'A particular order in which related events, movements, or things follow each other.', '/ˈsiː.kwəns/', '/ˈsiː.kwəns/', 'The common arithmetic sequence increases by adding a fixed constant value each step.', 'Calculate the exact twentieth term of the geometric distribution sequence.', '“A sequence is a chain of numbers following a secret pattern rule, like two, four, six, eight.”', 'Keep the ending crisp with an "s" sound, not a "z".', 'Preparatory School', 2),
('Substitute', 'يعوض / التعويض', 'Verb / Noun', 'سَابْسْتِتْيُوت', 'Sub·sti·tute', 'Sub: سَابْـ | sti: سْتِـ | tute: تْيُوتْ', 'To replace a variable or symbol in an algebraic expression with a specific numerical value.', 'A person or thing acting or serving in place of another individual or commercial entity.', '/ˈsʌb.stə.tuːt/', '/ˈsʌb.stɪ.tʃuːt/', 'Substitute x equals five into the quadratic equation to evaluate the final output.', 'The teacher demonstrated how to solve the linear system using the substitute method.', '“To substitute means to play like a sub in football! You take out the letter x and put a real number in its place.”', 'US accent uses /tuːt/, while UK accent often sounds like /tʃuːt/. Both are fully acceptable.', 'Primary / Preparatory', 2),
('Factor', 'العامل / يحيل إلى عوامل', 'Noun / Verb', 'فَاكْتُر', 'Fac·tor', 'Fac: فَاكْـ | tor: تُر', 'A number or algebraic expression that divides another number or expression evenly without a remainder.', 'A circumstance, fact, or influence that contributes explicitly to a final outcome.', '/ˈfæk.tər/', '/ˈfæk.tər/', 'The greatest common factor of twelve and eighteen is determined to be exactly six.', 'We must factor the quadratic trinomial expression completely before simplification.', '“A factor is a building block number. It multiplies with another number to create a bigger number product.”', 'Avoid pronouncing the ending with an Arabic accent; keep the /tər/ short and neutral.', 'Primary / Preparatory', 1),
('Polynomial', 'كثيرة الحدود', 'Noun / Adj', 'بُولِينَومِيَل', 'Pol·y·no·mi·al', 'Pol: بُو | y: لِـ | no: نُو | mi: مِـ | al: يَل', 'An algebraic expression consisting of several variable terms raised to non-negative integer powers.', 'A technical multidimensional algebraic sequence or complex function mapping.', '/ˌpɑː.liˈnoʊ.mi.əl/', '/ˌpɒl.iˈnəʊ.mi.əl/', 'The student calculated the first derivative of the given cubic polynomial function.', 'We need to perform polynomial long division to find the remaining function factors.', '“A polynomial is a long math train with many cars, where each car is a term with a variable and a power.”', 'Break it down into "Poly" (meaning many) and "nomial" (meaning terms) to help students learn it.', 'Preparatory / Secondary', 2),
('Matrix', 'المصفوفة', 'Noun', 'مِيتْرِكْس', 'Ma·trix', 'Ma: مِـي | trix: تْرِكْسْ', 'A rectangular array or grid of numbers, symbols, or expressions arranged in horizontal rows and vertical columns.', 'An organizational structure or environment in which something develops or originates.', '/ˈmeɪ.trɪks/', '/ˈmeɪ.trɪks/', 'To multiply two matrices together, the number of columns in the first must match the rows in the second.', 'Calculate the exact determinant value of the given three-by-three numeric matrix.', '“A matrix is like a mathematical grid or table filled with numbers arranged neatly in rows and columns.”', 'The plural form of "Matrix" is "Matrices" (pronounced /ˈmeɪ.تْرِ.سِيز/).', 'Secondary School', 2),
('Determinant', 'المحدد (للمصفوفة)', 'Noun', 'دِيتِرمِنَانْت', 'De·ter·mi·nant', 'De: دِ| ter: تِر | mi: مِـ | nant: نَانْتْ', 'A scalar numerical value calculated from a square matrix that encodes specific geometric and algebraic properties.', 'A factor that decisively affects the nature, direction, or outcome of a complex situation.', '/dɪˈtɜːr.mɪ.nənt/', '/dɪˈtɜː.mɪ.nənt/', 'If the determinant of a square matrix equals zero, the matrix is singular and has no inverse.', 'Compute the cross-multiplication determinant of the coefficients layout.', '“The determinant is a single special number we calculate from a square matrix grid that unlocks its secrets.”', 'The main phonetic stress falls clearly on the second syllable: /ˈtɜːr/.', 'Secondary School', 2),
('Vector', 'المتجه', 'Noun', 'فِكْتُر', 'Vec·tor', 'Vec: فِكْـ | tor: تُر', 'A mathematical quantity possessing both a definitive magnitude value and a definitive spatial direction.', 'A carrier or agent that transmits an infectious disease or algorithmic directional command.', '/ˈvek.tər/', '/ˈvek.tər/', 'We plotted the velocity vector on the Cartesian grid starting straight from the origin point.', 'Calculate the resultant vector by adding the corresponding horizontal components.', '“A vector is a math arrow. It tells you two critical things: how long or strong it is, and which way it points.”', 'Ensure the "V" sound is accurate and crisp, not soft or sliding into an "F".', 'Preparatory / Secondary', 2),
('Scalar', 'الكمية القياسية', 'Noun / Adj', 'سْكِيلَر', 'Sca·lar', 'Sca: سْكِـي | lar: لَر', 'A physical or mathematical quantity that possesses magnitude value but no definitive spatial direction.', 'A simple scaling factor or numeric multiplier used across vector operations.', '/ˈskeɪ.lər/', '/ˈskeɪ.lər/', 'Mass and temperature are standard examples of scalar fields in mathematical physics.', 'We performed scalar multiplication by multiplying every element of the vector by five.', '“A scalar is just a plain old single number, like five or ten. It has a size, but it doesn''t point anywhere.”', 'Keep the vowel long and clear on the first segment: /ˈskeɪ/.', 'Secondary School', 2),
('Logarithm', 'اللوغاريتم', 'Noun', 'لُوجَارِيثَم', 'Log·a·rithm', 'Log: لُو | a: جَـ | rithm: رِيثَمْ', 'The exponent or power to which a fixed base number must be raised to yield a given target number.', 'An algorithmic inverse calculation metric widely utilized across engineering codes.', '/ˈlɑː.ɡə.rɪ.ðəm/', '/ˈlɒɡ.ə.rɪ.ðəm/', 'The natural logarithm utilizes the mathematical constant e as its proportional base.', 'Apply the product rule of logarithms to simplify the complex exponential layout.', '“A logarithm answers the question: how many times do I need to multiply this base number to get that target number?”', 'The "th" makes a voiced sound here like the Arabic letter (ذ). Pronounce it as /ðəm/.', 'Secondary School', 2),
('Asymptote', 'المستقيم المقارب', 'Noun', 'أَسِيمْتُوت', 'As·ymp·tote', 'As: أَ | ymp: سِيمْـ | tote: تُوتْ', 'A straight continuous line that a geometric curve approaches indefinitely closer but never actually touches or intersects.', 'A theoretical boundary or operational limit that is closely neared but never fully reached.', '/ˈæs.ɪmptoʊt/', '/ˈæs.ɪmptəʊt/', 'The rational fraction function features a vertical asymptote situated at x equals negative two.', 'Plot the dashed horizontal asymptote on the Cartesian workspace grid.', '“An asymptote is a ghost line that a curve runs alongside. The curve gets closer and closer forever, but never touches it!”', 'The letter "p" is completely silent in regular speech. Pronounce it directly as "As-im-tote".', 'Secondary School', 2),
('Permutation', 'التبديل / التباديل', 'Noun', 'بِرمْيُوتِشَن', 'Per·mu·ta·tion', 'Per: بِر | mu: مْيُو | ta: تِـ | tion: شَن', 'An ordered arrangement of a specific set of items or numbers where the sequence order is critical.', 'The action of altering the relative arrangement or internal position of a set of items.', '/ˌpɜːr.mjuːˈteɪ.ʃən/', '/ˌpɜː.mjuːˈteɪ.ʃən/', 'Calculate the total number of permutations possible when choosing a three-digit lock code.', 'The permutation formula utilizes factorials to determine unique ordered configurations.', '“Permutations are picky! They care about the exact order of things, like the numbers in a safe combination.”', 'The primary stress lands on the third syllable: /ˈteɪ/.', 'Secondary School', 4),
('Combination', 'التوفيق / التوافيق', 'Noun', 'كَامْبِنِيشَن', 'Com·bi·na·tion', 'Com: كَامْـ | bi: بِـ | na: نِـي | tion: شَن', 'A selection of items chosen from a larger set where the sequence or choice order does not matter.', 'A joining or merging of different separate things, elements, or individual groups.', '/ˌkɑːm.bəˈneɪ.ʃən/', '/ˌkɒm.bɪˈneɪ.ʃən/', 'Choosing a committee of three students from a pool of ten is a classic combination problem.', 'The structural combination calculations are performed using the general n-Cr formula layout.', '“Combinations are easygoing! They don''t care about the order, like choosing a fruit salad mix.”', 'Differentiate explicitly between permutations (order matters) and combinations (order does not matter).', 'Secondary School', 4),

-- [51-70] مصطلحات الحساب والأعداد (Arithmetic & Numbers)
('Arithmetic', 'الحساب', 'Noun / Adj', 'أَرِيثْمِتِك', 'Ar·ith·me·tic', 'Ar: أَ | ith: رِيثْـ | me: مِـ | tic: تِكْ', 'The branch of mathematics dealing with the properties and manipulation of continuous numbers.', 'The practical utility of basic addition, subtraction, multiplication, and division operations.', '/əˈrɪθ.mə.tɪk/', '/əˈrɪθ.mə.tɪk/', 'Primary school students focus heavily on mastering foundational mental arithmetic skills.', 'The basic arithmetic operators include addition, subtraction, multiplication, and division symbols.', '“Arithmetic is the field of math where we play with numbers using adding, subtracting, and multiplying.”', 'When used as a noun, the stress lands on the second syllable: /əˈrɪθ.mə.tɪk/.', 'Primary School', 1),
('Integer', 'عدد صحيح', 'Noun', 'إِينْتِجُر', 'In·te·ger', 'In: إِينْـ | te: تِـ | ger: جُر', 'A whole number that can be positive, negative, or zero, without any fractional components.', 'A complete structural entity or whole non-divided corporate unit in analysis.', '/ˈɪn.t̬ə.dʒər/', '/ˈɪn.تِـ.جأر/', 'The solution set for this linear inequality must consist strictly of positive integers.', 'Negative numbers like negative five and negative ten are classified as valid integers.', '“An integer is a whole number with no fractions or decimals, like three, zero, or negative seven.”', 'Ensure the "g" sound is pronounced soft like a "j", not hard like a "g". It is "In-te-jer".', 'Primary / Preparatory', 1),
('Prime Number', 'عدد أولي', 'Noun', 'بْرَايْم نَامْبُر', 'Prime Num·ber', 'Prime: بْرَايْمْ | Num: نَامْـ | ber: بُر', 'A whole number strictly greater than one that cannot be formed by multiplying two smaller natural numbers.', 'A highly fundamental component or primary essential element within a framework.', '/ˈpraɪm ˈnʌm.bər/', '/ˈpraɪm ˈnʌm.bər/', 'The number two is unique because it is the only even prime number in existence.', 'List all the distinct prime numbers that are situated between twenty and fifty.', '“A prime number is a lonely number that can only be divided evenly by one and by itself, like seven.”', 'Remind students that the number one is historically NOT classified as a prime number.', 'Primary School', 1),
('Composite', 'عدد غير أولي / مؤلف', 'Adj / Noun', 'كَامْبَازِت', 'Com·pos·ite', 'Com: كَامْـ | pos: بَـا | ite: زِتْ', 'A positive whole number formed by multiplying two smaller positive integers, having factors other than one and itself.', 'Something made up of several different parts or composite structural elements.', '/kəmˈpɑː.zɪt/', '/ˈkɒm.pə.zɪt/', 'The number four is the smallest positive composite number available in arithmetic.', 'Every positive whole number is either a prime number or a composite number compound.', '“A composite number is a friendly number that has lots of factors, like six, which is two times three.”', 'US accent puts the main stress on the second segment: /kəmˈpɑː.zɪt/.', 'Primary School', 1),
('Rational', 'عدد نسبي', 'Adj', 'رَاشُونَل', 'Ra·tion·al', 'Ra: رَا | tion: شُـ | al: نَل', 'A number that can be explicitly written or expressed as a simple fraction ratio of two integers.', 'Based on or in clear accordance with reason, logic, or clear sane thinking.', '/ˈræʃ.ən.əl/', '/ˈræʃ.ən.əl/', 'Every terminating decimal represents a perfectly valid mathematical rational number.', 'The square root of two is clearly not a rational number layout.', '“A rational number is any number that can be written neatly as a fraction, like three-quarters.”', 'Avoid flat phonetic readings; maintain the soft /ʃ/ flow in the middle.', 'Preparatory School', 1),
('Irrational', 'عدد غير نسبي', 'Adj', 'إِيرَاشُونَل', 'Ir·ra·tion·al', 'Ir: إِيرْ | ra: رَا | tion: شُـ | al: نَل', 'A real number that cannot be expressed as a simple fraction ratio of two whole integers.', 'Not logical or reasonable, or acting without clear sound structural reasoning.', '/ɪˈræʃ.ən.əl/', '/ɪˈræʃ.ən.əl/', 'The mathematical constant pi is a famous example of an infinite irrational number.', 'The decimal expansion of an irrational number continues indefinitely without repeating patterns.', '“An irrational number is a crazy number that cannot be written as a fraction. Its decimals go on forever without stopping.”', 'Keep the initial double "r" sound fluid and continuous.', 'Preparatory School', 1),
('Divisible', 'قابل للقسمة على', 'Adj', 'دِفِيزِبَل', 'Di·vis·i·ble', 'Di: دِ| vis: فِـي | i: زِ| ble: بَل', 'Capable of being divided by another number cleanly without leaving any mathematical remainder.', 'Capable of being physically divided or separated into smaller structural components.', '/dɪˈvɪz.ə.bəl/', '/dɪˈvɪz.ə.bəl/', 'Any integer ending in zero or five is perfectly divisible by the number five.', 'Determine whether the large target value is cleanly divisible by three.', '“If you can divide a number by another number and get a clean answer with no remainder left over, it is divisible.”', 'Ensure the "s" is read with a soft "z" sound internally: /dɪˈvɪz/.', 'Primary School', 1),
('Remainder', 'الباقي (في القسمة)', 'Noun', 'رِيمِيدْنُر', 'Re·main·der', 'Re: رِ| main: مِـينْـ | der: دُر', 'The amount left over after performing an integer division operation that is not cleanly even.', 'A part, number, or quantity that is left over after other parts have been utilized.', '/rɪˈmeɪn.dər/', '/rɪˈmeɪn.dər/', 'Seven divided by three equals two with an absolute structural remainder of one.', 'If the calculation remainder equals zero, the divisor is a clean factor of the dividend.', '“The remainder is the leftover scrap piece when you share a number out into equal groups.”', 'Avoid sliding into flat dialect variants; keep the /meɪn/ segment elongated.', 'Primary School', 1),
('Absolute Value', 'القيمة المطلقة', 'Noun', 'أَبْسَلُوت فَالْيُو', 'Ab·so·lute Val·ue', 'Ab: أَبْـ | so: سَـ | lute: لُوتْ | Val: فَالْـ | ue: يـُو', 'The non-negative distance of a real number from the zero origin on a standard number line.', 'A principle or value that is universally true and not dependent on context.', '/ˈæb.sə.luːt ˈvæl.juː/', '/ˈæb.sə.luːt ˈvæl.juː/', 'The absolute value of negative five is completely identical to positive five.', 'Enclose the variable expression inside the parallel vertical absolute value bars.', '“The absolute value acts like a magic wash machine! It strips away negative signs and makes every number positive.”', 'Remind students that absolute value always represents physical distance, which cannot be negative.', 'Preparatory School', 1),
('Reciprocal', 'المقلوب (لعدد)', 'Noun / Adj', 'رِيسِبْرُوكَل', 'Re·cip·ro·cal', 'Re: رِ| cip: سِـبْـ | ro: رُو | cal: كَل', 'The mathematical multiplicative inverse of a number, found by flipping its fractional terms.', 'A mutual action or structural relationship given, felt, or done in return.', '/rɪˈsɪp.rə.kəl/', '/rɪˈsɪp.rə.kəl/', 'The reciprocal value of two-thirds is determined to be exactly three-halves.', 'Multiplying any non-zero number by its own reciprocal invariably yields exactly one.', '“To find the reciprocal of a fraction, just do a handstand! Flip it upside down so the bottom goes to the top.”', 'The stress falls firmly on the second syllable: /rɪˈsɪp/.', 'Primary / Preparatory', 1),
('Multiple', 'المضاعف', 'Noun / Adj', 'مَالْتِبَل', 'Mul·ti·ple', 'Mul: مَالْـ | ti: تِـ | ple: بَل', 'A number that may be divided by another a certain number of times without a remainder.', 'Numerous or involving many different parts, elements, or structural steps.', '/ˈmʌl.tə.pəl/', '/ˈmʌl.tɪ.pəl/', 'The numbers twelve, twenty-four, and thirty-six are valid multiples of twelve.', 'Find the least common multiple for the given fractional algebraic denominators.', '“Multiples are the numbers you land on when you skip-count! Like the multiples of five are five, ten, fifteen.”', 'Differentiate explicitly between a "factor" (building block) and a "multiple" (grown product).', 'Primary School', 1),
('Coefficient', 'المعامل', 'Noun', 'كُويِفِيشَنْت', 'Co·ef·fi·cient', 'Co: كُو | ef: إِفْ | fi: فِـي | cient: شَنْت', 'A numerical or constant quantity placed before and multiplying a variable.', 'A multiplier or factor that measures a specific structural property.', '/ˌkoʊ.ɪˈfɪʃ.ənt/', '/ˌkəʊ.ɪˈfɪʃ.ənt/', 'In the term three x, the number three is the coefficient.', 'Identify the variable coefficient.', '“The number multiplying the variable letter is the coefficient.”', 'Keep the middle syllable fluid.', 'Preparatory School', 2),
('Product', 'حاصل الضرب', 'Noun', 'بْرَادَاكْت', 'Prod·uct', 'Prod: بْرَا | uct: دَاكْتْ', 'The final numerical result obtained by multiplying two or more numbers together.', 'An article or substance that is manufactured or refined for commercial sale.', '/ˈprɑː.dʌkt/', '/ˈprɒd.ʌkt/', 'The product of four and five is calculated to be exactly twenty.', 'We need to compute the scalar product of the two algebraic functions.', '“Whenever you see the word product in a math story, it means the answer you get from multiplying numbers.”', 'Do not let students confuse "product" (multiplication answer) with "sum" (addition answer).', 'Primary School', 1),
('Quotient', 'خارج القسمة', 'Noun', 'كْوُوشَنْت', 'Quo·tient', 'Quo: كْوُ | tient: شَنْتْ', 'The final numerical result obtained by dividing one number by another divisor number.', 'A degree or specified amount of a quality or characteristic within an entity.', '/ˈkwoʊ.ʃənt/', '/ˈkwəʊ.ʃənt/', 'In the equation twelve divided by three equals four, the number four is the quotient.', 'Calculate the exact quotient before formatting the tracking decimal output.', '“The quotient is the grand answer you get when you finish a long division problem.”', 'Pronounce it as "Kwo-shent", keeping the vowel sounds crisp.', 'Primary School', 1),
('Sum', 'المجموع', 'Noun', 'سَام', 'Sum', 'Sum: سَامْ', 'The total numerical value result arrived at by adding two or more distinct amounts together.', 'A particular amount of money, or the total summary of a situation.', '/sʌm/', '/sʌm/', 'The total sum of all interior angles inside a planar square invariably equals 360 degrees.', 'Add the column numbers carefully to compute the absolute sum metrics.', '“The sum is the total answer you get when you pack numbers together using addition.”', 'Watch out for confusion with the homophone "some". This is "S-u-m".', 'Primary School', 1),
('Difference', 'الفرق (في الطرح)', 'Noun', 'دِيفِرَانْس', 'Dif·fer·ence', 'Dif: دِيفْـ | fer: رَ | ence: انْسْ', 'The final numerical result obtained by subtracting one quantity from another quantity value.', 'A point or way in which people or things are not completely alike or identical.', '/ˈdɪf.ɚ.əns/', '/ˈdɪf.ər.əns/', 'The exact difference between fifteen and seven is determined to be eight.', 'Calculate the difference in height between the two geometric cylinder modules.', '“Whenever a math problem asks for the difference, it wants you to subtract the smaller number from the bigger one.”', 'Keep the pronunciation running fast across the middle syllable; it sounds almost like "Dif-rens".', 'Primary School', 1),
('Estimation', 'التقدير / التخمين الرياضي', 'Noun', 'إِسْتِمِيشَن', 'Es·ti·ma·tion', 'Es: إِسْـ | ti: تِـ | ma: مِـي | tion: شَن', 'A rough calculation or approximation of the value, number, or quantity of something.', 'A judgment or commercial opinion of the worth, value, or quality of an entity.', '/ˌes.təˈmeɪ.ʃən/', '/ˌes.tɪˈmeɪ.ʃən/', 'We can use rounding parameters to perform a quick mental estimation of the final total cost.', 'The engineer''s estimation was within five percent of the final structural outcome.', '“An estimation is a smart guess! You use rounded numbers to find an answer that is close enough.”', 'The primary stress lands perfectly on the third syllable: /ˈmeɪ/.', 'Primary School', 1),
('Rounding', 'التقريب', 'Noun / Verb', 'رَاوْنْدِينْج', 'Round·ing', 'Round: رَاوْنْدْ | ing: إِنْج', 'Altering a number to a less exact but more convenient value based on nearby places.', 'The act of moving around a physical corner or making a shape circular.', '/ˈraʊn.dɪŋ/', '/ˈraʊn.dɪŋ/', 'Perform rounding on this long decimal value to the nearest hundredth place.', 'Rounding parameters help simplify extensive financial accounting reports data.', '“Rounding means making a number simpler by moving it to the nearest friendly ten or hundred.”', 'Ensure the "nd" cluster is voiced clearly before sliding into the ending.', 'Primary School', 1),
('Place Value', 'القيمة المكانية', 'Noun', 'بْلِيس فَالْيُو', 'Place Val·ue', 'Place: بْلِيسْ | Val: فَالْـ | ue: يـُو', 'The numerical value that a digit has by virtue of its position in a number sequence.', 'The explicit structural or commercial status of an element within a hierarchy.', '/ˈpleɪs ˈvæl.juː/', '/ˈpleɪs ˈvæl.juː/', 'In the number 532, the digit five holds a place value of exactly five hundred.', 'Students must master place value structures before moving to complex decimal additions.', '“The place value tells you how much a digit is worth just because of where it sits in the number house.”', 'Differentiate between "place value" (e.g., hundreds) and "value" (e.g., 500) for clarity.', 'Primary School', 1),
('Digit', 'الرقم (من 0 لـ 9)', 'Noun', 'دِيجِت', 'Dig·it', 'Dig: دِيجْـ | it: إِتْ', 'Any of the single numerals from zero to nine that form part of a larger number sequence.', 'A human finger or toe utilizing physical anatomical structures.', '/ˈdɪdʒ.ɪt/', '/ˈdɪdʒ.ɪt/', 'The telephone passcode must consist strictly of four distinct numeric digits.', 'Identify the missing digit in the tens column space of the equation.', '“A digit is a single number symbol from zero to nine. Numbers are built using digits, like words are built with letters!”', 'Pronounce both "i" vowels short and crisp, avoiding dragging the sound.', 'Primary School', 1),

-- [71-85] مصطلحات الإحصاء والاحتمالات (Statistics & Probability)
('Probability', 'الاحتمال', 'Noun', 'بْرُوبَابِيلِتِي', 'Prob·a·bil·i·ty', 'Prob: بْرُوبْ | a: بَا | bil: بِي | i: لِـ | ty: تِي', 'The mathematical calculus measuring the likelihood or chance that a specific event will occur, scaled between 0 and 1.', 'The extent to which something is statistically probable or likely to happen.', '/ˌprɑː.bəˈbɪl.ə.t̬i/', '/ˌprɒb.əˈbɪl.ə.ti/', 'The probability of tossing a fair coin and landing on heads is exactly point five.', 'We are analyzing the joint probability of independent distribution sequences.', '“If I roll a standard six-sided die, what is the probability of getting a number five? Excellent, it is one out of six.”', 'Ensure the primary phonetic stress lands perfectly on the third syllable: /bɪl/.', 'Preparatory / Secondary', 4),
('Graph', 'تمثيل بياني / منحنى', 'Noun', 'جْرَاف', 'Graph', 'Graph: جْرَاف', 'A diagrammatic representation showing the structural relation between variable quantities, typically along axes.', 'A visual collection of corporate data trends or analytical charts.', '/ɡræf/', '/ɡrɑːf/', 'The graph of a quadratic function forms a symmetric curve known as a parabola.', 'Plot the coordinate ordered pairs carefully on the Cartesian grid graph.', '“Let us plot these points on the grid to see the shape of our function graph.”', 'US accent uses the short /æ/ (Græf), while UK accent uses the long open /ɑː/ (Grɑːf). Both are completely correct.', 'Primary / Preparatory', 4),
('Statistics', 'الإحصاء', 'Noun', 'سْتَاتِيسْتِكْس', 'Sta·tis·tics', 'Sta: سْتَا | tis: تِيسْـ | tics: تِكْسْ', 'The systematic branch of mathematics dealing with data collection, analysis, interpretation, and presentation.', 'A collection of quantitative data or quantitative metrics regarding a situation.', '/stəˈtɪs.tɪks/', '/stəˈtɪs.tɪks/', 'The corporate marketing research relies heavily on comprehensive business statistics layouts.', 'We are using descriptive statistics parameters to summarize the student performance data.', '“Statistics is the field of math where we collect data, organize it, and study what it tells us about the world.”', 'Keep the double "t" structures sharp and audible.', 'Preparatory / Secondary', 4),
('Sample', 'العينة', 'Noun / Verb', 'سَامْبَل', 'Sam·ple', 'Sam: سَامْـ | ple: بَل', 'A small representative part or statistical subset chosen from a larger population data group.', 'To taste or try a small amount of something to analyze its quality.', '/ˈsæm.pəl/', '/ˈsɑːm.pəl/', 'The research team collected a random sample of one hundred independent corporate participants.', 'Ensure the data sample is completely unbiased to guarantee calculation accuracy.', '“A sample is a small group we pick from a big crowd to study, because we cannot test everyone one-by-one.”', 'US accent uses short /æ/ (Sæm-pel), UK uses open /ɑː/ (Sɑːm-pel).', 'Preparatory School', 4),
('Population', 'المجتمع الإحصائي', 'Noun', 'بُوبْيُلِيشَن', 'Pop·u·la·tion', 'Pop: بُوبْـ | u: يـُ | la: لِـي | tion: شَن', 'The entire universe or complete pool of items from which a statistical sample is drawn.', 'The total number of people inhabiting a specific city, country, or geographical area.', '/ˌpɑː.pjəˈleɪ.ʃən/', '/ˌpɒp.jəˈleɪ.ʃən/', 'The statistical population includes every single registered student within the educational district.', 'We need to infer the total population metrics based on our small sample indicators.', '“In math, a population means the whole giant group we want to know about, like all the fish in a lake.”', 'The primary stress falls on the third segment: /ˈleɪ/.', 'Preparatory School', 4),
('Variance', 'التباين (في الإحصاء)', 'Noun', 'فِيرِيَانْس', 'Var·i·ance', 'Var: فِـي | i: رِ| ance: يَنْسْ', 'A statistical measure of the dispersion or spread of a set of data points around their mean.', 'The state or fact of being completely different or divergent from a standard.', '/ˈver.i.əns/', '/ˈveə.ri.əns/', 'A low variance indicator shows that the data points are clustered closely around the calculated average.', 'Compute the statistical variance of the corporate distribution scores.', '“Variance tells us how spread out or scattered our numbers are from the central average score.”', 'Ensure the initial "V" sound is accurate, avoid shifting into an "F".', 'Secondary School', 4),
('Deviation', 'الانحراف (المعياري)', 'Noun', 'دِيفِإِيشَن', 'De·vi·a·tion', 'De: دِي | vi: فِـي | a: إِ| tion: شَن', 'The definitive absolute distance or structural difference between a single data point and the data mean.', 'The action of departing or turning away from an established path or standard.', '/ˌdiː.viˈeɪ.ʃən/', '/ˌdiː.viˈeɪ.ʃən/', 'The standard deviation parameter measures the average spread of scores in a statistical sample.', 'We recorded a significant deviation from the expected historical baseline trends.', '“Deviation is a measure of how far a number has wandered away from the middle average line.”', 'The plural is "Deviations". The stress hits the third segment: /ˈeɪ/.', 'Secondary School', 4),
('Histogram', 'المدرج التكراري', 'Noun', 'هِسْتُوجْرَام', 'His·to·gram', 'His: هِسْـ | to: تُو | gram: جْرَامْ', 'A specialized bar graph representation showing the distribution data grouped into continuous intervals.', 'A visual analytics configuration utilized to chart corporate data frequency metrics.', '/ˈhɪs.tə.ɡræm/', '/ˈhɪs.tə.ɡræm/', 'The histogram layout shows that the test scores are heavily skewed toward the higher intervals.', 'Construct a frequency histogram template based on the recorded raw data chart.', '“A histogram looks like a bar graph, but its bars are glued together side-by-side to show number ranges.”', 'Keep the middle vowel short and fast.', 'Primary / Preparatory', 4),
('Correlation', 'الارتباط (الإحصائي)', 'Noun', 'كُورِلِيشَن', 'Cor·re·la·tion', 'Cor: كُـو | re: رِ| la: لِـي | tion: شَن', 'A mutual statistical relationship or connection link between two or more variable quantities.', 'An interdependent structural connection where changes in one element align with changes in another.', '/ˌkɔːr.əˈleɪ.ʃən/', '/ˌkɒr.əˈleɪ.ʃən/', 'The data analysis reveals a strong positive correlation between study time and final test grades.', 'Remember class, statistical correlation does not automatically prove a definitive cause-and-effect relationship.', '“Correlation means that two things tend to change together, like temperature rising and ice cream sales growing.”', 'The stress falls firmly on the third syllable: /ˈleɪ/.', 'Secondary School', 4),
('Outlier', 'القيمة المتطرفة', 'Noun', 'أَوْتْلَايُر', 'Out·li·er', 'Out: أَوْتْ | li: لَا | er: يـُر', 'A data point data value that differs significantly and drastically from the remaining observations in a sample.', 'A person or structural thing situated completely away or detached from a main body group.', '/ˈaʊtˌlaɪ.ər/', '/ˈaʊtˌlaɪ.ər/', 'The exceptionally high test score recorded by one student represents a clear statistical outlier.', 'We must decide whether to exclude the outlier value to prevent biasing the mean.', '“An outlier is a rebel number that stands completely far away from all the other numbers in the list.”', 'Pronounce it as "Out-li-er", maintaining a clear diphthong sound on the middle part.', 'Preparatory School', 4),
('Probability', 'الاحتمالية', 'Noun', 'بْرُوبَابِيلِتِي', 'Prob·a·bil·i·ty', 'Prob: بْرُوبْ | a: بَا | bil: بِي | i: لِـ | ty: تِي', 'The likelihood of an event.', 'The chance of occurrence.', '/ˌprɑː.bəˈbɪl.ə.t̬i/', '/ˌprɒb.əˈbɪl.ə.ti/', 'The probability is high.', 'Calculate the core probability.', '“Probability is how likely something happens.”', 'Keep the stress on /bɪl/.', 'Preparatory School', 4),
('Data', 'البيانات', 'Noun', 'دِيتَا', 'Da·ta', 'Da: دِ| ta: تَا', 'A collection of facts, numbers, or information used for analysis and reference.', 'Corporate metrics or computational records stored inside a system.', '/ˈdeɪ.t̬ə/', '/ˈdeɪ.tə/', 'We collected the experimental data over a period of three full months.', 'The raw data must be organized into a spreadsheet before graphing.', '“Data is just a fancy word for pieces of information or numbers we collect to study.”', 'Can be pronounced as "Day-ta" (preferred in US) or "Dah-ta" (common in UK).', 'Primary School', 4),
('Survey', 'الاستبيان / استطلاع رأي', 'Noun / Verb', 'سِرفِـي', 'Sur·vey', 'Sur: سِر | vey: فِـي', 'An investigation or collection of data regarding the opinions or behavior of a group.', 'A comprehensive corporate inspection or mapping of a physical or structural layout.', '/ˈsɜːr.veɪ/', '/ˈsɜː.veɪ/', 'The students conducted a classroom survey to find out everyone''s favorite sport.', 'We need to analyze the feedback survey before launching the new distribution product.', '“A survey is a list of questions you ask a group of people to collect interesting data chunks.”', 'As a noun, the stress lands on the first syllable: /ˈsɜːr.veɪ/.', 'Primary / Preparatory', 4),
('Census', 'التعداد السكاني الإحصائي', 'Noun', 'سِينْسَس', 'Cen·sus', 'Cen: سِينْـ | sus: سَسْ', 'An official, comprehensive count or survey of a population, recording various details.', 'A complete structural audit or exhaustive collection of data across an entire universe.', '/ˈsen.səs/', '/ˈsen.səs/', 'The government conducts a national census every ten years to update demographic tracking data.', 'A census gathers data from every single member of the population, unlike a sample.', '“A census is when we count and study every single person in a country, with no exceptions.”', 'Keep both syllables short and clean, avoiding dragging the trailing vocal track.', 'Preparatory School', 4),
('Interval', 'الفترة / الفئة الإحصائية', 'Noun', 'إِينْتَرفَل', 'In·ter·val', 'In: إِينْـ | ter: تَر | val: فَل', 'The complete space or distance between two specified numeric values or programmatic limits.', 'A intervening period of time or a structural break between different business activities.', '/ˈɪn.t̬ər.vəl/', '/ˈɪn.tə.vəl/', 'The test scores were grouped into continuous intervals of ten marks each on the grid chart.', 'The function remains completely stable across the designated variable interval.', '“An interval is a number neighborhood, like all the numbers sitting between ten and twenty.”', 'The primary phonetic stress lands firmly on the first segment: /ˈɪn/.', 'Primary / Preparatory', 4),

-- [86-100] مصطلحات لغة الفصل والأوامر (Classroom Language & Operations)
('Solve', 'يحل / يـوجـد قـيـمـة', 'Verb', 'سُولْف', 'Solve', 'Solve: سُولْف', 'To calculate, discover, or deduce the correct numerical values or roots that satisfy a mathematical problem or equation.', 'To find an effective answer or explanation for a general dilemma or conflict.', '/sɑːlv/', '/sɒlv/', 'Students are required to solve the simultaneous linear system using elimination metrics.', 'Can you solve for y when x equals negative three?', '“Please open your notebooks and solve this equation step-by-step. Show all your work clearly.”', 'Do not confuse the verb "Solve" (الحل كفعل) with the noun "Solution" (الحل كاسم). Use them accurately.', 'Primary / Preparatory', 5),
('Simplify', 'يبسط', 'Verb', 'سِيمْبْلِفَاي', 'Sim·pli·fy', 'Sim: سِيمْ | pli: بْلِـ | fy: فَاي', 'To reduce an algebraic expression or numerical fraction to its minimal, most concise, and easily digestible form.', 'To make a complex concept or instruction easier to understand for people.', '/ˈsɪm.plə.faɪ/', '/ˈsɪm.plɪ.faɪ/', 'We can simplify the rational expression by factoring out and canceling the common scalar terms.', 'Always simplify your final fractional answer before submission.', '“Before you write down your final answer, check if you can simplify the fraction to its lowest terms.”', 'Remind students that simplifying an expression changes its visual form but never alters its actual core mathematical value.', 'Primary / Preparatory', 5),
('Calculate', 'يحسب', 'Verb', 'كَالْكْيُلِيت', 'Cal·cu·late', 'Cal: كَالْـ | cu: كْيُـ | late: لِيتْ', 'To determine a numerical value or mathematical result using computational arithmetic procedures.', 'To plan or intend a specific action with a precise corporate outcome in mind.', '/ˈkæl.kjə.leɪt/', '/ˈkæl.kjə.leɪt/', 'Calculate the total surface area of the complex polygonal structure carefully.', 'We must calculate the net profit percentage based on the distribution data charts.', '“Please calculate the total cost by adding these three numerical amounts together in your notebook.”', 'Keep the middle syllable short and soft, avoid drawing out the vocal transitions.', 'Primary School', 5),
('Evaluate', 'يوجد قيمة / يقيم', 'Verb', 'إِفَالْيُويْت', 'E·val·u·ate', 'E: إِ| val: فَالْـ | u: يـُ | ate: آيْتْ', 'To calculate the numerical value of an algebraic expression by substituting real numbers for variables.', 'To form an explicit judgment or assessment of the worth, value, or quality of an entity.', '/ɪˈvæl.ju.eɪt/', '/ɪˈvæl.ju.eɪt/', 'Evaluate the algebraic function when variable x is set to negative four.', 'Students will evaluate the structural proof layout during their mid-term assessment session.', '“To evaluate an expression, just plug in the given numbers and calculate the final single answer reward.”', 'The phonetic stress falls directly on the second syllable: /ɪˈvæl/.', 'Preparatory School', 5),
('Prove', 'يثبت / يبرهن', 'Verb', 'بْرُوف', 'Prove', 'Prove: بْرُوفْ', 'To demonstrate the absolute mathematical truth of a statement or theorem using a sequence of logical steps.', 'To demonstrate the existence, truth, or competency of something through evidence or arguments.', '/pruːv/', '/pruːv/', 'Can you prove that these two intersecting triangles are completely congruent to each other?', 'We will use geometric logic parameters to prove the Pythagorean theorem written on the board.', '“In geometry, we don''t just guess! We must prove our answers step-by-step using solid logical layout steps.”', 'Ensure the ending features a voiced "v" sound, not a sharp unvoiced "f". It is "Proove".', 'Preparatory School', 5),
('Graph', 'يمثل بيانياً (كفعل)', 'Verb', 'جْرَاف', 'Graph', 'Graph: جْرَاف', 'To plot points and draw a curve or line showing the structural relation between variables on a grid workspace.', 'To present corporate analytics or data tracking charts in a visual configuration.', '/ɡræf/', '/ɡrɑːf/', 'Graph the linear function equation carefully on your Cartesian coordinate grid worksheet.', 'We need to graph the recorded data trends to analyze the commercial distribution curves.', '“Please open your grid paper booklets and graph the solution coordinates we just calculated.”', 'Remind students to label both the horizontal x-axis and vertical y-axis whenever they graph.', 'Primary / Preparatory', 5),
('Plot', 'يعين نقطة / يرسم', 'Verb / Noun', 'بْلَات', 'Plot', 'Plot: بْلَاتْ', 'To mark precise point coordinates on a coordinate plane grid sheet using a pencil or software tool.', 'A secret plan made by a group, or a small piece of physical commercial land.', '/plɑːt/', '/plɒt/', 'Plot the ordered pair coordinates five comma negative two precisely on the grid workspace.', 'The student forgot to plot the final intercept point on the function line graph.', '“Take your pencil and plot a tiny dot exactly where the two grid lines cross together.”', 'US accent uses an open open /ɑː/ (Plat), while UK accent uses a rounded short /ɒ/ (Plot).', 'Primary School', 5),
('Deduce', 'يستنتج', 'Verb', 'دِيدْيُوس', 'De·duce', 'De: دِ| duce: دْيُوسْ', 'To arrive at a fact or a specific mathematical conclusion by reasoning logically from general principles.', 'To trace the structural course or historical origin of an element within an operational framework.', '/dɪˈduːs/', '/dɪˈdʒuːs/', 'From the given geometric indicators, we can easily deduce that line AB is parallel to CD.', 'Deduce the ultimate value of the algebraic constant using the elimination rules.', '“Look closely at the clues given in the geometry drawing. What can you deduce about this missing angle?”', 'The second syllable uses a long /uː/ or /juː/ track, ending with a sharp "s" hiss sound.', 'Preparatory School', 5),
('Define', 'يعرّف / يحدد بدقة', 'Verb', 'دِيفَايْن', 'De·fine', 'De: دِ| fine: فَايْنْ', 'To state precisely the exact mathematical meaning or structural properties of a term or concept.', 'To mark out the boundary limits or core definitive features of a physical or commercial framework.', '/dɪˈfaɪn/', '/dɪˈfaɪn/', 'Please define the absolute difference between a proper fraction and an improper fraction layout.', 'We must define the operational variable terms clearly before starting the equation execution.', '“Who can raise their hand and define what an acute angle means in geometry? Excellent definition!”', 'Keep the pronunciation running smoothly with the stress hitting the second segment: /faɪn/.', 'Primary / Preparatory', 5),
('Compare', 'يقارن', 'Verb', 'كَمْبِير', 'Com·pare', 'Com: كَمْـ | pare: بِيرْ', 'To estimate, measure, or note the similarity or dissimilarity between two or more mathematical entities.', 'To look at different commercial or structural items to estimate their relative value or status.', '/kəmˈper/', '/kəmˈpeər/', 'Compare the two fractional numbers using the standard greater than, less than, or equal symbols.', 'We need to compare the statistical variance indicators across both sample populations.', '“Look at these two decimals on the board. Let us compare them to see which number value is bigger.”', 'Ensure the middle vowel transitions rise cleanly without sliding into flat regional variants.', 'Primary School', 5),
('Contrast', 'يباين / يوضح الاختلاف', 'Verb / Noun', 'كَانْتْرَاسْت', 'Con·trast', 'Con: كَانْـ | trast: تْرَاسْتْ', 'To explicitly compare two mathematical concepts or shapes to emphasize their specific structural differences.', 'The state of being strikingly different from something else in structural juxtaposition.', '/kənˈtræst/', '/kənˈtrɑːst/', 'Contrast the core properties of a regular square with the structural setup of a geometric rhombus.', 'The lesson template will contrast descriptive statistics with advanced inferential metrics structures.', '“In today''s geometry quiz, I want you to contrast a rectangle and a trapezoid. Show me how they differ!”', 'As a verb, the stress lands on the second syllable: /kənˈtræst/.', 'Preparatory School', 5),
('Illustrate', 'يوضح بالرسم أو الأمثلة', 'Verb', 'إِلَسْتْرِيت', 'Il·lus·trate', 'Il: إِ| lus: لَسْـ | trate: تْرِيتْ', 'To explain or make a mathematical concept completely clear by using drawings, diagrams, or examples.', 'To provide physical commercial artwork or visual assets for a story or textbook format.', '/ˈɪl.ə.streɪt/', '/ˈɪl.ə.streɪt/', 'The teacher used an interactive geometric app to illustrate how the reflection system behaves.', 'Illustrate the algebraic distribution formula step-by-step using a colored grid worksheet layout.', '“Let me draw a big circle pie on the whiteboard to illustrate how we slice up fractions visually.”', 'The primary stress lands on the very first syllable: /ˈɪl/. Don''t say "il-lus-trate".', 'Primary School', 5),
('Verify', 'يتأكد / يتحقق من صحة', 'Verb', 'فِيرِفَاي', 'Ver·i·fy', 'Ver: فِـيرْ | i: ِـ | fy: فَايْ', 'To check and prove that a mathematical calculation or equation result is completely correct.', 'To demonstrate the truth or competency of an item through structural verification processes.', '/ˈver.ə.faɪ/', '/ˈver.ɪ.faɪ/', 'Always verify your computed algebraic roots by substituting them back into the original equation.', 'We performed a cross-check routine to verify the coordinates data integrity on the chart grid.', '“Once you finish calculating your answer, plug it back into the equation box to verify it is correct!”', 'Ensure the initial "V" is voiced correctly, avoiding flattening the sound into an "F".', 'Primary / Preparatory', 5),
('Identify', 'يحدد / يتعرف على', 'Verb', 'أيْدِينْتِفَاي', 'I·den·ti·fy', 'I: أيْـ | den: دِينْـ | ti: تِـ | fy: فَايْ', 'To establish or indicate who or what a specific geometric shape, number, or expression is.', 'To recognize and name a specific commercial or structural element within a larger tracking layout.', '/aɪˈden.t̬ə.faɪ/', '/aɪˈden.tɪ.faɪ/', 'Identify all the acute angles present inside the irregular polygonal drawing written on the board.', 'Students must identify the independent variable factor before graphing the continuous function line.', '“Look closely at this list of whole numbers. Can you identify which numbers are prime numbers?”', 'The stress falls firmly on the second syllable: /aɪˈden/.', 'Primary School', 5),
('Label', 'يسمي / يضع تسمية على الرسم', 'Verb / Noun', 'لِيبَل', 'La·bel', 'La: لِـي | bel: بَلْ', 'To assign alphanumeric letters or names to the vertices, sides, or axes of a geometric drawing grid.', 'A small piece of commercial material affixed to an object to indicate its operational identity.', '/ˈleɪ.bəl/', '/ˈleɪ.bəl/', 'Label the horizontal axis as variable x and the vertical axis as variable y on the graph.', 'Do not forget to label every vertex point of your regular pentagon construction layout carefully.', '“When you finish drawing your triangle corner layout, use big capital letters to label the vertices A, B, and C.”', 'Keep the vocal layout flowing smoothly, without dragging the trailing consonant cluster.', 'Primary School', 5);
